import { useEffect, useState } from "react";
import API_URL from "../api"; // Import backend URL

function Profile() {
  const [capsules, setCapsules] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [user, setUser] = useState(null);

  useEffect(() => {
    const fetchUserData = async () => {
      const token = localStorage.getItem("token");

      if (!token) {
        setError("You are not authenticated. Please log in.");
        setLoading(false);
        return;
      }

      try {
        // Fetch user profile
        const userResponse = await fetch(`${API_URL}/api/user/profile`, {
          headers: { Authorization: `Bearer ${token}` },
        });

        if (!userResponse.ok) throw new Error("Failed to fetch user profile.");

        const userData = await userResponse.json();
        setUser(userData);

        // Fetch user's capsules
        const response = await fetch(`${API_URL}/api/memoryhaven`, {
          headers: { Authorization: `Bearer ${token}` },
        });

        if (!response.ok) throw new Error("Failed to fetch capsules.");

        const data = await response.json();
        setCapsules(data);
      } catch (error) {
        console.error("Error fetching data:", error);
        setError(error.message);
      } finally {
        setLoading(false);
      }
    };

    fetchUserData();
  }, []);

  return (
    <div className="profile-container">
      <h1>❤️ <strong>Your Profile</strong> ✨</h1>

      {loading ? (
        <p className="loading">Loading...</p>
      ) : error ? (
        <p className="error">Error: {error}</p>
      ) : user ? (
        <div className="profile-info">
          <img src={user.profilePic || "/default-avatar.png"} alt="Profile" className="profile-pic" />
          <p><strong>Name:</strong> {user.name}</p>
          <p><strong>Email:</strong> {user.email}</p>
          <p><strong>Joined:</strong> {new Date(user.createdAt).toDateString()}</p>
        </div>
      ) : null}

      <h2>📜 <strong>Your Capsules</strong></h2>

      {loading ? (
        <p>Loading capsules...</p>
      ) : error ? (
        <p className="error">Error: {error}</p>
      ) : capsules.length > 0 ? (
        <div className="capsule-grid">
          {capsules.map(capsule => (
            <div className="capsule-card" key={capsule._id}>
              <h3>{capsule.title}</h3>
              <p>{capsule.description}</p>
              <small>{new Date(capsule.date).toDateString()}</small>
              <button>View Capsule</button>
            </div>
          ))}
        </div>
      ) : (
        <p>You haven't created any capsules yet. <a href="/create">Create one now!</a></p>
      )}
    </div>
  );
}

export default Profile;
